import { Component } from '@angular/core';
import { FormControl, FormGroup, Validators,FormsModule } from '@angular/forms';
import { Router } from '@angular/router';
import { HttpService } from 'src/app/http.service';
import { customer } from '../customers/customers.interface'



@Component({
  selector: 'app-add-customer',
  templateUrl: './add-customer.component.html',
  styleUrls: ['./add-customer.component.scss']
})
export class AddCustomerComponent {

  form?: FormGroup;
  data: customer []= [];

  newCustomer = new FormGroup({
    firsName: new FormControl('', [
        Validators.required,
        Validators.minLength(4),
        Validators.maxLength(50),
    ]),
    lastName: new FormControl('', [
      Validators.required,
      Validators.minLength(3),
      Validators.maxLength(20),

    ]),
    email: new FormControl('', [
        Validators.required,
        Validators.email,
    ]),
    phone: new FormControl('', [
        Validators.required,
        Validators.minLength(4),
        Validators.maxLength(20),
    ]),
});



   addCustomer() {
    const sub = this.http.post<customer>("customers", this.newCustomer.value).subscribe(data => {
      this.newCustomer;
      sub.unsubscribe();
      console.log(data);
  });


            console.log("עובד");

}

  constructor (private http: HttpService){}

  ngOnInit(){
      const sub = this.http.post<customer[]>("customers",this.addCustomer).subscribe(data => {
          this.data = data;
          sub.unsubscribe();
      });
  }
  }







<p>עובד</p>

<h1> הוספת לקוח</h1>

<form [formGroup]="newCustomer">
    <div class="field">
        <label><i class="fa fa-user"></i> שם פרטי:</label>
        <input class="w3-input w3-border w3-round" type="text" FormControlName="fullName">
    </div>

    <div class="field">
        <label><i class="fa fa-envelope"></i> שם משפחה:</label>
        <input class="w3-input w3-border w3-round" type="text" FormControlName="email">
    </div>

    <div class="field">
        <label><i class="fa fa-user"></i>אימייל:</label>
        <input class="w3-input w3-border w3-round" type="text" FormControlName="userName">
    </div>

    <div class="field">
        <label><i class="fa fa-asterisk"></i> טלפון:</label>
        <input class="w3-input w3-border w3-round" type="text" FormControlName="password">
    </div>


    <button class="w3-btn w3-green w3-round w3-block"  (click)="addCustomer()">צור לקוח <i class="fa fa-check"></i></button>



</form>
